import{c as s,o as r,b as n}from"./index-XiHV-P3j.js";const l="/docs/image.webp",i="/docs/accounts.webp",g="/docs/add.webp",p="/docs/add_success.webp",c="/docs/info.webp",a="/docs/tariff.webp",d="/docs/account_modal.webp",e="/docs/qr_code.webp",m="/docs/accountsv2.webp",_="/docs/a_modal.webp",h={class:"markdown-body"},k={__name:"Подключение мессенджеров в Личном Кабинете",setup(u,{expose:o}){return o({frontmatter:{}}),(w,t)=>(r(),s("div",h,[...t[0]||(t[0]=[n('<h2>1. Вход в личный кабинет</h2><ol><li>Перейдите на страницу входа по ссылке: <a href="https://www.google.com/search?q=https://app.whatsapi.ru/login">https://app.whatsapi.ru/login</a></li><li>Введите ваши <strong>логин</strong> и <strong>пароль</strong>.</li><li>Если вы забыли пароль, нажмите <strong>«Сбросить пароль»</strong> и следуйте инструкциям, которые придут на вашу электронную почту.</li></ol><p><img src="'+l+'" alt="Описание картинки"></p><h2>2. Добавление нового аккаунта мессенджера</h2><p>В меню личного кабинета нажмите кнопку <strong>«+ Добавить аккаунт»</strong>. В появившемся окне «Настройка интеграции» выполните следующие действия:</p><p><img src="'+i+'" alt="Описание картинки"></p><ul><li><p>Выберите тип мессенджера, который хотите подключить: <img src="'+g+'" alt="Описание картинки"><img src="'+p+'" alt="Описание картинки"></p></li><li><p><strong>Выберите мессенджер:</strong> (например, WhatsApp или Max)</p></li><li><p>Нажмите кнопку <strong>«Сохранить»</strong>.</p></li></ul><blockquote><p><strong>Проверьте состояние вашей подписки:</strong></p><ul><li>Если подписка активна — продолжайте подключение.</li><li>Если нет — оформите подписку через раздел <strong>«Действие»</strong> → <strong>«Подписка»</strong> → <strong>«Оплатить»</strong> (стоимость тарифа, например Max 1 Month, составляет <strong>2 200 ₽/мес</strong>). <img src="'+c+'" alt="Описание картинки"><img src="'+a+'" alt="Описание картинки"></li></ul></blockquote><h2>3. Активация аккаунта</h2><ol><li>В списке аккаунтов найдите нужный и в колонке «Действие» выберите пункт <strong>«Включить»</strong>. <img src="'+d+'" alt="Описание картинки"></li><li>На экране появится <strong>QR-код</strong>. Откройте мессенджер на вашем телефоне и отсканируйте этот код. <img src="'+e+'" alt="Описание картинки"></li><li>После успешного сканирования статус аккаунта изменится на <strong>«Включен»</strong> (зеленый индикатор).</li></ol><h2>4. Просмотр и управление аккаунтами</h2><p>В разделе <strong>«Аккаунты»</strong> отображается таблица со списком всех подключений. <img src="'+m+'" alt="Описание картинки"></p><h3>Статусы аккаунта:</h3><table><thead><tr><th>Индикатор</th><th>Статус</th><th>Описание</th></tr></thead><tbody><tr><td>🟢</td><td><strong>Включен</strong></td><td>Аккаунт работает корректно.</td></tr><tr><td>🔴</td><td><strong>Отключен</strong></td><td>Аккаунт временно неактивен.</td></tr><tr><td>🟡</td><td><strong>Связь разорвана</strong></td><td>Требуется повторная активация (сканирование QR-кода).</td></tr></tbody></table><h3>Статусы подписки:</h3><ul><li><strong>Активна до [дата]</strong> — аккаунт будет работать до указанного срока.</li><li><strong>Не требуется активации</strong> — аккаунт готов к использованию.</li><li><strong>Активировать</strong> — необходимо оплатить тариф и выполнить активацию.</li></ul><h3>Возможные действия с аккаунтом:</h3><p><img src="'+_+'" alt="Описание картинки"> Через кнопку меню в колонке «Действие» доступны следующие опции:</p><ul><li><strong>Подписка</strong> — управление оплатой и тарифом.</li><li><strong>Настройки</strong> — изменение внутренних параметров аккаунта.</li><li><strong>Сменить имя</strong> — редактирование отображаемого названия.</li><li><strong>Включить / Выключить</strong> — запуск или приостановка работы шлюза.</li><li><strong>Сбросить</strong> — удаление текущих настроек для подключения другого номера телефона.</li><li><strong>Сменить прокси</strong> — изменение сетевых настроек для аккаунта.</li><li><strong>Удалить аккаунт</strong> — полное удаление записи из личного кабинета.</li></ul>',19)])]))}};export{k as default};
